// Sinh tu file Word. Khoa = nam (truong y cua moc); timeline.js doc window.TIMELINE_DETAIL[m.y].
window.TIMELINE_DETAIL = {
    "1885":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Không cam chịu sự đầu hàng của triều đình, phe chủ chiến trong triều đình Huế do Thượng thư bộ Binh Tôn Thất Thuyết đứng đầu đã bí mật tích trữ vũ khí, tổ chức cuộc tấn công trại lính Pháp ở đồn Mang Cá kinh hoàng đêm 4/7/1885. Cuộc tấn công không thành, Tôn Thất Thuyết hộ giá vua trẻ Hàm Nghi rời kinh thành chạy ra căn cứ Tân Sở (Quảng Trị).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến phong trào:\u003c/strong\u003e Tại đây, thay mặt nhà vua, Tôn Thất Thuyết ban chiếu Cần Vương (Hết lòng giúp vua cứu nước). Chiếu Cần Vương nhanh chóng thổi bùng ngọn lửa yêu nước, thổi bùng hàng loạt cuộc khởi nghĩa vũ trang quy mô lớn khắp Bắc Kỳ và Trung Kỳ dưới sự lãnh đạo của các sĩ phu, văn thân:\u003c/p\u003e\u003cp\u003eKhởi nghĩa Hương Khê (Phan Đình Phùng, Cao Thắng - chế tạo súng trường theo mẫu Pháp)\u003c/p\u003e\u003cp\u003eKhởi nghĩa Ba Đình (Đinh Công Tráng)\u003c/p\u003e\u003cp\u003eKhởi nghĩa Bãi Sậy (Nguyễn Thiện Thuật).\u003c/p\u003e\u003cp\u003ePhong trào kéo dài đến năm 1896 khi Phan Đình Phùng hy sinh mới chính thức khép lại.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Phong trào yêu nước chống Pháp vĩ đại nhất dưới ngọn cờ tư tưởng phong kiến, khẳng định tấm lòng kiên trung son sắt vì đại nghĩa dân tộc của các sĩ phu.\u003c/p\u003e",
    "1771":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Đến nửa sau thế kỷ XVIII, cả hai chính quyền Đàng Ngoài và Đàng Trong đều lâm vào tình trạng mục nát tột cùng. Ở Đàng Trong, quyền thần Trương Phúc Loan chuyên quyền bóc lột, thuế má nặng nề khiến đời sống nhân dân vô cùng cực khổ.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eBùng nổ phong trào:\u003c/strong\u003e Năm 1771, ba anh em Nguyễn Nhạc, Nguyễn Lữ, Nguyễn Huệ rời quê nhà đến vùng Tây Sơn thượng đạo (An Khê, Gia Lai) lập căn cứ khởi nghĩa. Họ đưa ra khẩu hiệu hợp lòng dân: \"Lấy của nhà giàu chia cho dân nghèo\", nhanh chóng thu hút hàng vạn nông dân, dân nghèo đô thị và cả các đồng bào dân tộc thiểu số tham gia.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự nghiệp phi thường:\u003c/strong\u003e Với thiên tài quân sự của Nguyễn Huệ, nghĩa quân Tây Sơn đã lập nên những kỳ tích vô tiền khoáng hậu: lật đổ chính quyền chúa Nguyễn ở Đàng Trong, sau đó tiến quân ra Bắc lật đổ tập đoàn chúa Trịnh cai trị hàng trăm năm, xóa bỏ ranh giới sông Gianh, bước đầu thống nhất lại giang sơn.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Là một trong những phong trào nông dân vĩ đại và thành công nhất trong lịch sử Việt Nam, đập tan các tập đoàn phong kiến mục nát, chuẩn bị tiền đề cho việc nhất thống đất nước.\u003c/p\u003e",
    "1285":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Năm 1285, Hốt Tất Liệt (vua nhà Nguyên) huy động một lực lượng khổng lồ lên tới 50 vạn quân do con trai là Thoát Hoan chỉ huy tiến công Đại Việt từ phía Bắc, kết hợp cánh quân của Toa Đô đánh từ phía Nam (Chăm-pa) lên, quyết tâm phục thù. Trước thế giặc mạnh như vũ bão, Thượng hoàng Trần Thánh Tông đã triệu tập Hội nghị Diên Hồng để hỏi ý kiến các bô lão trong thiên hạ nên \"Hòa\" hay \"Đánh\". Toàn thể hội trường đồng thanh hô vang: \"ĐÁNH!\".\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến cuộc chiến:\u003c/strong\u003e Tiết chế Trần Hưng Đạo viết \"Hịch tướng sĩ\" đánh động lòng yêu nước của binh lính, ai nấy đều xăm lên tay hai chữ \"Sát Thát\" (Giết giặc Mông Cổ). Quân ta kiên trì thực hiện rút lui chiến lược, chịu đựng sức ép ghê gớm từ hai đầu Nam - Bắc. Khi quân địch mệt mỏi, phân tán lực lượng vì nắng nóng và dịch bệnh bùng phát, quân Trần phát động tổng phản công dồn dập tại Tây Kết, Hàm Tử, Chương Dương.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eKết quả:\u003c/strong\u003e Cánh quân phía Nam bị tiêu diệt, tướng Toa Đô bị chém đầu. Chủ tướng Thoát Hoan hốt hoảng phải chui vào ống đồng để quân lính khiêng tháo chạy qua biên giới để tránh tên tẩm độc của quân ta.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Đỉnh cao của tinh thần đại đoàn kết toàn dân tộc (\"Vua tôi đồng lòng, anh em hòa mục, cả nước góp sức\").\u003c/p\u003e",
    "938":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Kiều Công Tiễn phản bội, giết hại Tiết độ sứ Dương Đình Nghệ để đoạt chức. Bị nhân dân căm ghét, Kiều Công Tiễn hoảng sợ đã hèn hạ sang cầu viện nhà Nam Hán. Vua Nam Hán sai con trai là Lưu Hoằng Tháo chỉ huy một hạm đội chiến thuyền khổng lồ theo đường biển tiến vào xâm lược nước ta.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eNghệ thuật quân sự thiên tài:\u003c/strong\u003e Ngô Quyền – con rể của Dương Đình Nghệ – nhanh chóng đem quân từ Thanh Hóa ra Bắc, tiêu diệt tên phản tặc Kiều Công Tiễn trước khi giặc tới. Nhận định cửa sông Bạch Đằng có địa hình hiểm trở, thủy triều lên xuống mạnh, Ngô Quyền nảy ra kế sách độc đáo: cho quân vát nhọn hàng nghìn thân cây gỗ lớn, bịt đầu sắt, cắm xuống lòng sông tạo thành trận địa cọc ngầm dưới nước.\u003c/p\u003e\u003cp class=\"tl-dia\"\u003e[Thủy triều lên: Cọc ngầm bị che khuất] ---\u0026gt; Ngô Quyền cho thuyền nhẹ ra khiêu chiến, dụ địch vào sâu trong sông.\u003c/p\u003e\u003cp class=\"tl-dia\"\u003e[Thủy triều rút: Cọc sắt lộ ra]      ---\u0026gt; Quân ta tổng phản công quyết liệt. Thuyền giặc đâm vào cọc nhọn vỡ tan tành.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eKết quả:\u003c/strong\u003e Toàn bộ chiến thuyền Nam Hán bị nhấn chìm, tướng giặc Lưu Hoằng Tháo tử trận tại chỗ. Vua Nam Hán kinh hoàng, từ bỏ hoàn toàn mộng xâm lược.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Chiến thắng vĩ đại kết thúc hoàn toàn hơn 1.000 năm Bắc thuộc tối tăm, mở ra kỷ nguyên độc lập, tự chủ vĩnh viễn cho dân tộc Việt Nam.\u003c/p\u003e",
    "1972":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Nhằm cứu vãn thế trận thất bại trên chiến trường miền Nam và ép chính phủ Việt Nam Dân chủ Cộng hòa phải ký một bản Hiệp định Paris có lợi cho Mỹ, cuối tháng 12/1972, Tổng thống Mỹ Nixon ra lệnh mở chiến dịch Linebacker II – cuộc tập kích chiến lược bằng đường hàng không quy mô lớn nhất lịch sử bằng siêu pháo đài bay B-52 rải thảm hủy diệt Hà Nội, Hải Phòng và các thành phố lớn.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến cuộc chiến:\u003c/strong\u003e Trong suốt 12 ngày đêm (từ 18/12 đến 30/12/1972), bầu trời Hà Nội rực lửa pháo hoa đạn tên lửa. Với sự chuẩn bị chu đáo từ trước về chiến thuật đánh B-52 của lực lượng Phòng không - Không quân cùng tinh thần quả cảm kiên cường của nhân dân thủ đô, quân dân ta đã bắn rơi 81 máy bay các loại, trong đó có tới 34 siêu pháo đài bay B-52 (được coi là biểu tượng bất khả chiến bại của không lực Hoa Kỳ).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Được thế giới ngợi ca là chiến thắng \"Điện Biên Phủ trên không\". Chiến công lẫy lừng này đã bẻ gãy hoàn toàn uy lực không quân Mỹ, buộc Mỹ phải chấm dứt hoàn toàn đánh phá miền Bắc, cúi đầu quay lại bàn đàm phán để ký kết Hiệp định Paris theo các điều khoản của ta.\u003c/p\u003e",
    "-179":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau khi dùng kế ly gián (Trọng Thủy - Mỵ Châu) đánh bại An Dương Vương, Triệu Đà sáp nhập đất đai Âu Lạc vào nước Nam Việt.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eChính sách cai trị:\u003c/strong\u003e Chia đất nước thành 2 quận: Giao Chỉ và Cửu Chân. Triệu Đà áp đặt hệ thống cai trị gián tiếp thông qua các Lạc tướng bản địa cũ nhưng bắt đầu thu thuế bóc lột các sản vật quý hiếm như ngọc trai, ngà voi, sừng tê giác để cống nộp.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa giai đoạn:\u003c/strong\u003e Đây là điểm khởi đầu của ách đô hộ ngoại bang, kích hoạt dòng máu phản kháng mạnh mẽ của nhân dân.\u003c/p\u003e",
    "-2879":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sự phát triển của công cụ lao động bằng đồng và sự gia tăng dân số tại lưu vực các dòng sông lớn đòi hỏi phải có một tổ chức quản lý xã hội chung để làm thủy lợi, trị thủy và chống giặc ngoại xâm. Theo truyền thuyết, Kinh Dương Vương gây dựng cơ đồ, truyền đến Lạc Long Quân - Âu Cơ sinh ra bọc trăm trứng, người con trưởng lên ngôi hiệu là Hùng Vương.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eTổ chức \u0026amp; Đời sống:\u003c/strong\u003e Nhà nước sơ khai Văn Lang đóng đô tại Phong Châu (Phú Thọ). Xã hội chia thành 15 bộ lạc lớn. Bộ máy cai trị đứng đầu là Hùng Vương (cha truyền con nối), giúp việc có các Lạc hầu (văn) và Lạc tướng (võ), đứng đầu các làng xã (bộ chính) là các Bồ chính. Kinh tế dựa hoàn toàn vào nông nghiệp trồng lúa nước, kết hợp săn bắn, hái lượm và nghề đúc đồng sơ khai.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eHệ quả \u0026amp; Ý nghĩa:\u003c/strong\u003e Đặt nền móng đầu tiên cho quốc gia độc lập, định hình ý thức hệ \"đồng bào\" và cội nguồn dân tộc Việt Nam.\u003c/p\u003e",
    "1945":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử chớp thời cơ vàng:\u003c/strong\u003e Tháng 8/1945, phát-xít Nhật bị quân Đồng minh đánh bại, buộc phải tuyên bố đầu hàng vô điều kiện. Quân Nhật ở Đông Dương hoang mang cực độ, chính phủ bù nhìn Trần Trọng Kim rệu rã. Điều kiện khách quan chín muồi xuất hiện, lịch sử gọi là \"Thời cơ nghìn năm có một\". Đảng và Mặt trận Việt Minh lập tức phát lệnh Tổng khởi nghĩa trên toàn quốc với tinh thần: \"Dù có phải đốt cháy cả dãy Trường Sơn cũng phải kiên quyết giành cho được độc lập!\".\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến thần tốc:\u003c/strong\u003e Chỉ trong vòng 15 ngày (từ 14/8 đến 28/8/1945), hơn 20 triệu nhân dân cả nước đồng loạt nổi dậy giành chính quyền tại các đô thị lớn: Hà Nội (19/8), Huế (23/8), Sài Gòn (25/8). Ngày 30/8, vua Bảo Đại làm lễ thoái vị, trao ấn kiếm cho phái đoàn chính phủ cách mạng, chấm dứt chế độ phong kiến.\u003c/p\u003e\u003cp class=\"tl-dia\"\u003e[19/8]: Giành chính quyền ở Hà Nội ---\u0026gt; [23/8]: Giành chính quyền ở Huế ---\u0026gt; [25/8]: Giành chính quyền ở Sài Gòn\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eTuyên ngôn Độc lập:\u003c/strong\u003e Ngày 2/9/1945, tại Quảng trường Ba Đình (Hà Nội), Chủ tịch Hồ Chí Minh đọc bản Tuyên ngôn Độc lập, trang trọng tuyên bố trước toàn thế giới sự khai sinh của nước Việt Nam Dân chủ Cộng hòa.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Đập tan ách thống trị hơn 80 năm của thực dân Pháp và 5 năm của phát-xít Nhật, lật đổ chế độ phong kiến kéo dài hàng thiên niên kỷ, đưa nhân dân Việt Nam từ thân phận nô lệ bước lên địa vị làm chủ đất nước.\u003c/p\u003e",
    "-257":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Vào thế kỷ III TCN, nhà Tần ở phương Bắc mở rộng bờ cõi xuống phía Nam. Để đối phó với kẻ thù chung, tộc người Âu Việt (ở phía Bắc) và Lạc Việt (ở phía Nam) đã liên kết lại.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến \u0026amp; Tổ chức:\u003c/strong\u003e Thục Phán – thủ lĩnh tộc Âu Việt – có công lao lớn trong cuộc kháng chiến chống Tần, đã hợp nhất hai tộc người, lên ngôi lấy hiệu là An Dương Vương, đặt tên nước là Âu Lạc, chuyển kinh đô từ vùng núi Phong Châu xuống vùng đồng bằng Cổ Loa (Đông Anh, Hà Nội ngày nay). Ông cho xây dựng thành Cổ Loa với kiến trúc vòng xoắn ốc độc đáo, trang bị vũ khí nỏ liên châu (nỏ thần).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eHệ quả \u0026amp; Ý nghĩa:\u003c/strong\u003e Bước tiến lớn về kỹ thuật quân sự và tư duy phòng thủ quốc gia. Tuy nhiên, do chủ quan và mất cảnh giác trước mưu kế của Triệu Đà (vua nước Nam Việt), Âu Lạc thất thủ vào năm 179 TCN, mở đầu thời kỳ Bắc thuộc đen tối.\u003c/p\u003e",
    "1930":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau khi tiếp cận chủ nghĩa Mác - Lênin, Nguyễn Ái Quốc (Nguyễn Tất Thành) tích cực truyền bá lý luận cách mạng giải phóng dân tộc vào trong nước thông qua Hội Việt Nam Cách mạng Thanh niên. Đến cuối năm 1929, phong trào công nhân và yêu nước phát triển mạnh mẽ dẫn đến sự ra đời của ba tổ chức cộng sản biệt lập ở ba miền (Đông Dương Cộng sản Đảng, An Nam Cộng sản Đảng, Đông Dương Cộng sản Liên đoàn). Ba tổ chức này hoạt động công kích, tranh giành ảnh hưởng lẫn nhau, có nguy cơ gây chia rẽ lớn.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eHội nghị thống nhất Đảng:\u003c/strong\u003e Từ ngày 6/1 đến ngày 7/2/1930, với tư cách là phái viên của Quốc tế Cộng sản, Nguyễn Ái Quốc đã chủ trì Hội nghị hợp nhất các tổ chức cộng sản tại Cửu Long (Hương Cảng, Trung Quốc). Hội nghị đồng lòng thống nhất các tổ chức thành một đảng duy nhất lấy tên là Đảng Cộng sản Việt Nam, thông qua Chánh cương vắn tắt, Sách lược vắn tắt do Nguyễn Ái Quốc soạn thảo.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Là kết quả của sự kết hợp nhuần nhuyễn giữa chủ nghĩa Mác - Lênin, phong trào công nhân và phong trào yêu nước. Sự kiện chấm dứt hoàn toàn thời kỳ khủng hoảng lãnh đạo kéo dài, đưa cách mạng Việt Nam trở thành một bộ phận khăng khít của cách mạng thế giới.\u003c/p\u003e",
    "1785":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau khi bị quân Tây Sơn đánh bại, chúa Nguyễn Ánh (hậu duệ nhà Nguyễn) đã sang Xiêm (Thái Lan) cầu viện. Vua Xiêm chớp cơ hội liền sai hai tướng Chiêu Tăng và Chiêu Sương thống lĩnh 5 vạn quân thủy bộ cùng hơn 300 chiến thuyền sang xâm lược vùng Gia Định (Nam Bộ), dọc đường đi chúng đốt phá, cướp bóc vô cùng tàn bạo.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eTrận địa mai phục thiên tài:\u003c/strong\u003e Nhận được tin, tháng 1/1785, Nguyễn Huệ từ Quy Nhơn kéo quân vào Nam. Ông khảo sát địa hình sông Tiền và chọn đoạn sông từ Rạch Gầm đến Xoài Mút (Tiền Giang ngày nay) làm trận địa mai phục do nơi đây lòng sông rộng, hai bên bờ cây cối rậm rạp, thích hợp bố trí hỏa lực tầm xa.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến \u0026amp; Kết quả:\u003c/strong\u003e Nguyễn Huệ cho quân dùng chiến thuật khiêu chiến, dụ hạm đội chiến thuyền của quân Xiêm lọt thỏm vào trận địa mai phục lúc rạng sáng ngày 20/1/1785. Ngay lập tức, pháo binh Tây Sơn từ hai bên bờ và các đảo nổi đồng loạt khai hỏa dồn dập. Các chiến thuyền Tây Sơn từ các ngả lao ra chia cắt đội hình giặc. Chỉ trong vài giờ, 5 vạn quân Xiêm bị tiêu diệt gần như hoàn toàn, chỉ còn vài nghìn tên sống sót chạy tháo chạy đường bộ về nước. Nguyễn Ánh phải chạy trốn sang các đảo xa.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Đập tan âm mưu xâm lược của phong kiến Xiêm, khẳng định tài năng quân sự xuất chúng của Nguyễn Huệ trong nghệ thuật đánh thủy chiến dứt điểm.\u003c/p\u003e",
    "248":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Thế kỷ III, nhà Đông Ngô (thời Tam Quốc) siết chặt ách cai trị đối với Giao Châu, bóc lột tận cùng sức người và sản vật.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến cuộc chiến:\u003c/strong\u003e Năm 248, tại vùng núi Nưa (Triệu Sơn, Thanh Hóa), anh em Triệu Thị Trinh (Bà Triệu) và Triệu Quốc Đạt tập hợp nghĩa quân nổi dậy. Khi ra trận, Bà Triệu thường mặc áo giáp vàng, đi guốc ngà, cài trâm vàng, cưỡi voi chiến, khiến quân Ngô kinh hồn bạt vía. Câu nói bất hủ của bà truyền lại cho hậu thế:\u003c/p\u003e\u003cp class=\"tl-q\"\u003e\"Tôi muốn cưỡi cơn gió mạnh, đạp luồng sóng dữ, chém cá kình ở biển Đông, đánh đuổi quân Ngô, giành lại giang sơn, cởi ách nô lệ, chứ không chịu khom lưng quỳ gối làm tì thiếp người ta!\"\u003c/p\u003e\u003cp\u003eNhà Ngô phải phái danh tướng Lục Dập mang hơn 8.000 quân sang dùng cả mưu kế hiểm độc và tiền bạc mua chuộc để chia rẽ nghĩa quân. Cuối cùng, Bà Triệu đã anh dũng hy sinh trên núi Tùng (Hậu Lộc, Thanh Hóa).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Tiếp nối ngọn lửa đấu tranh giải phóng dân tộc, là minh chứng cho tinh thần kiên cường không chịu khuất phục của người phụ nữ Việt.\u003c/p\u003e",
    "1418":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Ách đô hộ tàn bạo của nhà Minh đẩy nhân dân ta vào cảnh khốn cùng. Khắp nơi nổ ra các cuộc khởi nghĩa (tiêu biểu như nhà Hậu Trần) nhưng đều bị đàn áp đẫm máu do thiếu đường lối lãnh đạo thống nhất.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eQuá trình chiến đấu gian khổ:\u003c/strong\u003e Mùa xuân năm 1418, tại vùng núi Lam Sơn (Thanh Hóa), hào trưởng Lê Lợi cùng nhà quân sự, ngoại giao lỗi lạc Nguyễn Trãi cùng 18 chí sĩ yêu nước (Hội thề Lũng Nhai) chính thức phất cờ khởi nghĩa, Lê Lợi tự xưng là Bình Định Vương. Thời gian đầu, nghĩa quân gặp muôn vàn khó khăn, liên tục bị vây hãm tại núi Chí Linh, có lúc cạn kiệt lương thực phải ăn củ mài, giết ngựa chiến. Nhờ chiến lược chuyển địa bàn hoạt động vào nghệ An (theo mưu kế của Nguyễn Chích) năm 1424, nghĩa quân tạo bước ngoặt, giải phóng toàn bộ vùng đất phía Nam.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eTổng phản công quyết định:\u003c/strong\u003e Nghĩa quân tiến quân ra Bắc, bao vây thành Đông Quan (Hà Nội). Những đại thắng vang dội tại Tốt Động - Chúc Động (1426) và Chi Lăng - Xương Giang (1427) đã chém chết Liễu Thăng, nghiền nát 15 vạn quân cứu viện của nhà Minh. Lê Lợi thể hiện tinh thần nhân đạo cao cả, mở hội thề Đông Quan, cấp thuyền và ngựa cho hàng vạn quân Minh bại trận rút lui an toàn về nước.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Cuộc chiến tranh giải phóng dân tộc trường kỳ kéo dài 10 năm thắng lợi hoàn toàn, đập tan ách đô hộ của nhà Minh, giành lại độc lập tự chủ tối cao.\u003c/p\u003e",
    "1558":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau khi Nguyễn Kim qua đời, người con rể là Trịnh Kiểm độc chiếm toàn bộ quyền hành Nam triều, ra tay sát hại người con trưởng của Nguyễn Kim để trừ họa hậu họa. Người con thứ là Nguyễn Hoàng lo sợ cho tính mạng của mình, nghe theo lời khuyên của Trạng Trình Nguyễn Bỉnh Khiêm: \"Hoành Sơn nhất đới, vạn đại dung thân\" (Một dải Hoành Sơn có thể dung thân muôn đời), đã xin vào trấn thủ vùng đất Thuận Hóa (miền Trung ngày nay) vào năm 1558.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eCục diện chia cắt kéo dài:\u003c/strong\u003e Nguyễn Hoàng và các chúa Nguyễn kế tiếp ra sức khai phá vùng đất phía Nam, xây dựng lực lượng cát cứ riêng biệt, gọi là Đàng Trong. Ở phía Bắc, họ Trịnh lập phủ Chúa độc chiếm binh quyền, vua Lê chỉ còn là bù nhìn (vua Lê - chúa Trịnh), gọi là Đàng Ngoài. Từ năm 1627 đến năm 1672, hai bên Trịnh - Nguyễn đã phát động 7 cuộc chiến tranh quy mô lớn, lấy Sông Gianh (Quảng Bình) làm ranh giới chia cắt giang sơn.\u003c/p\u003e\u003cp class=\"tl-dia\"\u003e[ĐÀNG NGOÀI]: Vua Lê - Chúa Trịnh cai trị Bắc Bộ (đến Sông Gianh)\u003c/p\u003e\u003cp\u003e\u003cstrong\u003e================== RANH GIỚI:\u003c/strong\u003e SÔNG GIANH (QUẢNG BÌNH) ==================\u003c/p\u003e\u003cp class=\"tl-dia\"\u003e[ĐÀNG TRONG]: Các Chúa Nguyễn cai trị Trung Bộ \u0026amp; Nam Bộ\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Giai đoạn chia cắt đau thương dài nhất trong lịch sử, kìm hãm sự phát triển chung của đất nước, nhưng vô hình trung lại đẩy mạnh quá trình mở rộng bờ cõi về phương Nam (Nam tiến) của các chúa Nguyễn.\u003c/p\u003e",
    "544":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Đầu thế kỷ VI, nhà Lương cai trị Giao Châu. Thứ sử Tiêu Tư tàn bạo độc ác khiến lòng dân căm phẫn tích tụ sâu sắc.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eThành lập nhà nước tự chủ:\u003c/strong\u003e Năm 542, Lý Bí (Lý Nam Đế) – một hào trưởng địa phương – liên kết với các hào kiệt khắp nơi (như Triệu Quang Phục, Tinh Thiều) nổi dậy khởi nghĩa. Chỉ trong vòng vài tháng, nghĩa quân đánh đuổi Tiêu Tư, giải phóng hoàn toàn lãnh thổ. Đầu năm 544, Lý Bí lên ngôi Hoàng đế (Lý Nam Đế), đặt quốc hiệu là Vạn Xuân (với mong muốn đất nước độc lập mãi muôn đời xuân), đóng đô ở cửa sông Tô Lịch, xây dựng điện Vạn Thọ và chùa Khai Quốc (chùa Trấn Quốc ngày nay).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến tiếp theo:\u003c/strong\u003e Nhà Lương lại đem quân sang xâm lược. Lý Nam Đế trao quyền bính cho Triệu Quang Phục. Triệu Quang Phục rút quân về vùng đầm lầy Dạ Trạch (Khoái Châu, Hưng Yên), dùng chiến thuật du kích ban đêm đánh tiêu hao sinh lực địch, được nhân dân tôn xưng là Dạ Trạch Vương. Đến năm 550, ông đánh đuổi được quân Lương, giữ vững nền tự chủ đến năm 602 trước khi bị nhà Tùy thôn tính.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Lần đầu tiên người Việt xây dựng một triều đình phong kiến độc lập hoàn chỉnh, tự xưng Hoàng đế ngang hàng với các hoàng đế Trung Hoa, đập tan tư tưởng bá quyền của phương Bắc.\u003c/p\u003e",
    "1428":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lập quốc:\u003c/strong\u003e Đất nước sạch bóng quân thù, năm 1428, Lê Lợi lên ngôi hoàng đế (Lê Thái Tổ), khôi phục quốc hiệu Đại Việt, mở ra triều đại Hậu Lê (Lê sơ). Nguyễn Trãi viết bản \"Bình Ngô Đại Cáo\" – bản Tuyên ngôn Độc lập thứ hai của dân tộc:\u003c/p\u003e\u003cp class=\"tl-q\"\u003e\"Như nước Đại Việt ta từ trước,\u003c/p\u003e\u003cp\u003eVốn xưng nền văn hiến đã lâu.\u003c/p\u003e\u003cp\u003eNúi sông bờ cõi đã chia,\u003c/p\u003e\u003cp\u003ePhong tục Bắc Nam cũng khác.\"\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eThời kỳ cực thịnh:\u003c/strong\u003e Triều đại đạt đến đỉnh cao hoàng kim dưới sự trị vì của vua Lê Thánh Tông (1460–1497). Ông thực hiện những cải cách hành chính vĩ đại, chia đất nước thành 13 đạo thừa tuyên, khôi phục hệ thống khoa cử nghiêm ngặt, mở rộng lãnh thổ về phía Nam, thành lập Tao đàn Nhị thập bát tú. Xã hội thái bình ổn định, kinh tế phát triển vượt bậc.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Là giai đoạn chế độ quân chủ chuyên chế tập quyền trung ương ở Việt Nam đạt đến độ hoàn thiện, quy củ và thịnh vượng nhất trong lịch sử phong kiến.\u003c/p\u003e",
    "722":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Thời kỳ nhà Đường đô hộ Giao Châu (bấy giờ đổi tên thành An Nam đô hộ phủ). Chính sách cống nộp đặc sản gắt gao, đặc biệt là việc bắt phu dịch gánh quả vải thiều từ nước ta sang kinh đô Trường An của nhà Đường giữa mùa hè nóng nực.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến:\u003c/strong\u003e Không chịu nổi nhục nhã nô lệ, Mai Thúc Loan (vốn là một phu gánh vải, quê ở Hà Tĩnh) đã hô hào các phu dịch nổi dậy. Ông chọn vùng Sa Nam (Nam Đàn, Nghệ An) làm căn cứ, xây dựng thành Vạn An. Ông liên kết với nhân dân Chăm-pa, Chân Lạp tạo thành liên minh mạnh mẽ, giải phóng thành Tống Bình (Hà Nội). Ông lên ngôi, được nhân dân tôn kính gọi là Mai Hắc Đế (Vua Đen - do ông có nước da ngăm đen khỏe mạnh). Nhà Đường sau đó cử Dương Tư Húc đem 10 vạn quân sang đàn áp dã man bằng những thủ đoạn tàn độc.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Thể hiện tinh thần liên minh quốc tế khu vực chống kẻ thù chung và ý chí quật khởi mạnh mẽ của tầng lớp dân nghèo khổ nhất xã hội.\u003c/p\u003e",
    "1911":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Các phong trào yêu nước chống Pháp từ cuối thế kỷ XIX đến đầu thế kỷ XX, từ khởi nghĩa vũ trang phong kiến (Cần Vương, khởi nghĩa Yên Thế của Hoàng Hoa Thám) đến các xu hướng cải cách dân chủ tư sản (Đông Du của Phan Bội Châu, Duy Tân của Phan Châu Trinh) đều lần lượt thất bại bế tắc. Cách mạng Việt Nam rơi vào cuộc khủng hoảng sâu sắc về đường lối lãnh đạo.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện lịch sử:\u003c/strong\u003e Người thanh niên yêu nước Nguyễn Tất Thành (với lòng yêu nước thương dân sâu sắc và tư duy độc lập độc đáo, không tán thành con đường của các bậc tiền bối) đã quyết định phải đi sang chính các nước phương Tây để tìm hiểu xem họ làm cách nào để giàu mạnh, rồi trở về giúp đồng bào. Ngày 5/6/1911, tại Bến cảng Nhà Rồng (Sài Gòn), dưới cái tên Văn Ba, anh xin làm phụ bếp trên chiếc tàu buôn Đô đốc Latouche-Tréville, chính thức bắt đầu hành trình vạn dặm xuyên qua nhiều đại lục, đại dương.\u003c/p\u003e\u003cp class=\"tl-dia\"\u003e[5/6/1911 - Bến Nhà Rồng] ---\u0026gt; Xuất phát với bàn tay trắng ---\u0026gt; Đi qua Pháp, Anh, Mỹ, các nước châu Phi, châu Mỹ ---\u0026gt; Tìm ra chân lý cứu nước.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Bước ngoặt vĩ đại nhất của lịch sử cách mạng Việt Nam thế kỷ XX, đặt viên gạch đầu tiên tìm ra con đường giải phóng dân tộc đúng đắn nhất: con đường cách mạng vô sản.\u003c/p\u003e",
    "968":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau khi Ngô Quyền mất (944), đất nước rơi vào tình trạng phân rã cát cứ trầm trọng, lịch sử gọi là Loạn 12 sứ quân. Các thế lực phong kiến đánh giết lẫn nhau làm kinh tế kiệt quệ, nhân dân lầm than, đẩy đất nước trước nguy cơ bị nhà Tống xâm lược.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự nghiệp thống nhất giang sơn:\u003c/strong\u003e Đinh Bộ Lĩnh (người động Hoa Lư, Ninh Bình), với tài năng quân sự xuất chúng và sự hậu thuẫn của nhân dân, đã dùng các biện pháp vừa đánh vừa dụ, liên kết chính trị. Chỉ trong vài năm, ông dẹp tan hoàn toàn 12 sứ quân, thống nhất đất nước, được tôn xưng là Vạn Thắng Vương. Năm 968, ông lên ngôi Hoàng đế (Đinh Tiên Hoàng), đặt quốc hiệu là Đại Cồ Việt (Nước Việt Lớn), đóng đô tại Hoa Lư, đúc đồng tiền đầu tiên “Thái Bình hưng bảo”.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Khẳng định vị thế tối cao bằng danh xưng \"Hoàng đế\" ngang hàng phương Bắc, chấm dứt thời kỳ phân tán bè phái, xây dựng nhà nước quân chủ tập quyền đầu tiên vững mạnh.\u003c/p\u003e",
    "-111":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Nhà Hán (Hán Vũ Đế) tiêu diệt nhà Triệu, thôn tính toàn bộ nước Nam Việt bao gồm cả vùng đất Âu Lạc cũ.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eChính sách đồng hóa sâu sắc:\u003c/strong\u003e Nhà Hán chia lại đất nước thành 3 quận: Giao Chỉ, Cửu Chân, Nhật Nam, gộp cùng 6 quận của Trung Quốc thành Giao Châu. Chúng cử các quan Thái thú người Hán sang cai trị trực tiếp (tiêu biểu như Tô Định), mở trường dạy chữ Hán, áp đặt Nho giáo, luật pháp nhà Hán, cưỡng chế thay đổi phong tục tập quán của người Việt theo lối sống phương Bắc.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eHệ quả:\u003c/strong\u003e Mâu thuẫn sắc tộc và mâu thuẫn giai cấp đẩy lên đỉnh điểm, tạo tiền đề bùng nổ cho các cuộc chính biến vũ trang.\u003c/p\u003e",
    "1954":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau 8 năm sa lầy quân sự, năm 1953, Pháp áp dụng kế hoạch Navarre nhằm giành lại thế chủ động chiến lược. Được Mỹ viện trợ tài chính khổng lồ, Pháp đã xây dựng tại Điện Biên Phủ (một thung lũng lòng chảo hiểm trở ở Tây Bắc) một tập đoàn cứ điểm quân sự mạnh nhất Đông Dương với 49 cứ điểm, hệ thống hỏa lực phòng thủ dày đặc, thách thức quân đội ta tiến công.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eQuyết định lịch sử \u0026amp; Diễn biến:\u003c/strong\u003e Bộ Chính trị quyết định mở chiến dịch Điện Biên Phủ, cử Đại tướng Võ Nguyên Giáp làm tổng chỉ huy. Với nhãn quan quân sự thiên tài, Đại tướng quyết định thay đổi phương châm chiến lược từ \"Đánh nhanh thắng nhanh\" sang \"Đánh chắc tiến chắc\" ngay trước giờ nổ súng. Hàng vạn dân công ngày đêm xẻ núi, kéo những khẩu pháo nặng hàng tấn lên đỉnh đèo cao bằng sức người, đào hàng trăm cây số đường hào bao vây siết chặt quân địch. Chiến dịch diễn ra trong 56 ngày đêm (từ 13/3 đến 7/5/1954), chia làm 3 đợt tấn công đẫm máu bẻ gãy từng phân khu phòng thủ của địch.Chiều ngày 7/5/1954, lá cờ \"Quyết chiến quyết thắng\" tung bay trên nóc hầm tướng De Castries, toàn bộ bộ chỉ huy tập đoàn cứ điểm Pháp bị bắt sống.\u003c/p\u003e\u003cp class=\"tl-dia\"\u003e[13/3/1954]: Nổ súng mở màn chiến dịch ---\u0026gt; [56 ngày đêm khoét núi ngủ hầm] ---\u0026gt; [7/5/1954]: Tướng De Castries đầu hàng\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e \"Nên vành hoa đỏ, nên thiên sử vàng\", đập tan hoàn toàn ý chí xâm lược của thực dân Pháp, buộc Pháp phải ký Hiệp định Geneva (21/7/1954), tôn trọng độc lập, chủ quyền của Việt Nam, mở đầu cho sự sụp đổ của hệ thống thuộc địa kiểu cũ trên toàn thế giới.\u003c/p\u003e",
    "1986":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau mười năm thống nhất (1975-1985), do hậu quả nặng nề của chiến tranh kéo dài, chính sách bao vây cấm vận ngặt nghèo của Mỹ, cùng những sai lầm chủ quan duy ý chí trong chính sách quản lý kinh tế (áp dụng mô hình kinh tế kế hoạch hóa tập trung bao cấp gò bó, triệt tiêu động lực sản xuất), nền kinh tế Việt Nam lâm vào cuộc khủng hoảng kinh tế - xã hội trầm trọng, lạm phát phi mã lên tới hơn 700% vào năm 1986, đời sống nhân dân vô cùng thiếu thốn, khốn khổ.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eBước ngoặt vĩ đại:\u003c/strong\u003e Tháng 12/1986, tại Đại hội toàn quốc lần thứ VI của Đảng, dưới sự lãnh đạo của Tổng Bí thư Nguyễn Văn Linh, Đảng đã dũng cảm nhìn thẳng vào sự thật, đánh giá đúng sự thật và đề ra đường lối Đổi mới toàn diện đất nước. Trọng tâm là đổi mới về kinh tế: xóa bỏ triệt để cơ chế tập trung quan liêu bao cấp, chuyển sang phát triển nền kinh tế thị trường định hướng xã hội chủ nghĩa, mở rộng nền kinh tế nhiều thành phần, khuyến khích tư nhân và thu hút vốn đầu tư nước ngoài.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Cột mốc cứu nguy phát triển mang tính sống còn đối với vận mệnh quốc gia, cởi trói hoàn toàn cho sức sản xuất, giúp Việt Nam nhanh chóng thoát khỏi khủng hoảng, từ một nước thiếu ăn phải nhập khẩu gạo trở thành một trong những quốc gia xuất khẩu nông sản hàng đầu thế giới, đời sống nhân dân cải thiện vượt bậc.\u003c/p\u003e",
    "2007":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau hơn 20 năm thực hiện công cuộc Đổi mới thành công, nền kinh tế Việt Nam đã lớn mạnh vượt bậc và có độ mở cao, nhu cầu tham gia vào sân chơi thương mại tự do toàn cầu lớn nhất hành tinh trở nên vô cùng cấp thiết để hưởng các ưu đãi thuế quan và thu hút dòng vốn đầu tư xuyên quốc gia. Việt Nam đã trải qua tiến trình đàm phán ròng rã suốt 11 năm với các tiêu chuẩn khắt khe.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện:\u003c/strong\u003e Ngày 11/1/2007, Việt Nam chính thức được kết nạp, trở thành thành viên thứ 150 của Tổ chức Thương mại Thế giới (WTO).\u003c/p\u003e\u003cp class=\"tl-dia\"\u003e[11 năm đàm phán kiên trì] ---\u0026gt; [11/1/2007]: Trở thành thành viên thứ 150 của WTO ---\u0026gt; Hội nhập sâu rộng toàn cầu\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Cột mốc đỉnh cao khẳng định Việt Nam đã hội nhập hoàn toàn, bình đẳng vào hệ thống kinh tế, thương mại toàn cầu. Sự kiện mở toang cánh cửa thu hút dòng vốn FDI khổng lồ, thúc đẩy kim ngạch xuất nhập khẩu tăng trưởng thần tốc, đưa vị thế kinh tế và chính trị của Việt Nam lên tầm cao mới vững chắc trên trường quốc tế.\u003c/p\u003e",
    "1010":  "\u003cp\u003e\u003cstrong\u003eBối cảnh \u0026amp; Tư duy chiến lược:\u003c/strong\u003e Ý thức được vùng núi hiểm trở Hoa Lư (Ninh Bình) chỉ thích hợp cho việc phòng thủ quân sự thời kỳ đầu độc lập mà hạn chế sự giao thương, phát triển kinh tế. Năm 1010, Lý Thái Tổ viết bản \"Chiếu dời đô\" (Thiên đô chiếu) có tầm nhìn xuyên thế kỷ.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện:\u003c/strong\u003e Ông quyết định di chuyển kinh đô từ Hoa Lư về thành Đại La (Hà Nội ngày nay). Truyền thuyết kể rằng khi thuyền rồng vừa cập bến dưới chân thành, vua nhìn thấy hình ảnh một con rồng vàng bay vút lên trời cao, liền đổi tên thành là Thăng Long (Rồng bay lên).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Thể hiện bước chuyển lớn từ tư duy phòng thủ sang tư duy phát triển toàn diện, biến Thăng Long trở thành trái tim chính trị, kinh tế, văn hóa trường tồn của dân tộc cho đến tận ngày nay.\u003c/p\u003e",
    "1407":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Lợi dụng việc Hồ Quý Ly cướp ngôi nhà Trần, nhà Minh (Trung Quốc) lấy danh nghĩa “Phù Trần diệt Hồ” đã huy động 20 vạn quân do Trương Phụ chỉ huy tiến sang xâm lược nước ta.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến \u0026amp; Thất bại:\u003c/strong\u003e Nhà Hồ tổ chức kháng chiến kiên cường, xây dựng phòng tuyến kiên cố dọc sông Hồng và đúc súng thần cơ (do Hồ Nguyên Trừng sáng chế). Tuy nhiên, do không tập hợp được lòng dân như nhà Trần từng làm, đúng như lời Hồ Nguyên Trừng từng nói: \"Thần không sợ đánh, chỉ sợ lòng dân không theo mà thôi\". Sức kháng cự của nhà Hồ nhanh chóng tan vỡ vào năm 1407, cha con Hồ Quý Ly bị bắt giải sang Trung Quốc.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eChính sách cai trị bạo tàn:\u003c/strong\u003e Nhà Minh xóa bỏ quốc hiệu Đại Ngu, đổi thành quận Giao Chỉ, biến nước ta thành một tỉnh của Trung Quốc. Chúng thực hiện chính sách đồng hóa văn hóa tàn bạo chưa từng có: đốt sạch tất cả các sách vở lịch sử văn hóa của người Việt, đập phá bia đá, bắt hàng vạn thợ thủ công tài hoa (như Nguyễn An) sang Trung Quốc phục dịch, vơ vét từng thỏi vàng, hạt ngọc. Nhân dân rơi vào cảnh: \"Nướng dân đen trên ngọn lửa hung tàn / Vùi con đỏ xuống dưới hầm tai vạ\".\u003c/p\u003e",
    "1905":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sang đầu thế kỷ XX, sau khi dập tắt các cuộc khởi nghĩa Cần Vương, Pháp bắt tay vào cuộc khai thác thuộc địa lần thứ nhất tàn bạo. Các tư tưởng tiến bộ từ bên ngoài (Tân thư, cuộc duy tân Minh Trị ở Nhật Bản, Cách mạng Tân Hợi ở Trung Quốc) tràn vào nước ta làm thay đổi nhận thức của các sĩ phu yêu nước thế hệ mới.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến sự kiện:\u003c/strong\u003e Năm 1904, nhà chí sĩ Phan Bội Châu thành lập Duy Tân hội. Với tư tưởng muốn dùng bạo động vũ trang để đánh Pháp và nhận định Nhật Bản là nước cùng màu da, cùng văn hóa Đông Á đã tự cường thành công, năm 1905, ông phát động phong trào Đông Du (Đi về phía Đông). Phong trào đã vận động, tổ chức thành công cho hơn 200 du học sinh, thanh niên Việt Nam yêu nước sang Nhật Bản học tập về khoa học, quân sự hiện đại để chờ ngày về cứu nước. Đến năm 1908, thực dân Pháp câu kết ngoại giao với Chính phủ Nhật Bản, khiến phong trào bị trục xuất, tan rã.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Đánh dấu bước chuyển dịch quan trọng từ tư duy cứu nước phong kiến lối mòn sang xu hướng dân chủ tư sản hiện đại, khơi dậy tinh thần hiếu học, mở mang tầm nhìn ra thế giới của thanh niên.\u003c/p\u003e",
    "1789":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau khi chúa Trịnh sụp đổ, vị vua cuối cùng của nhà Hậu Lê là Lê Chiêu Thống đã hèn hạ chạy sang Trung Quốc cầu viện nhà Thanh. Vua Thanh (Càn Long) lập tức sai Tổng đốc Lưỡng Quảng Tôn Sĩ Nghị thống lĩnh 29 vạn quân chia làm 4 ngả tràn sang xâm lược Đại Việt với âm mưu thôn tính nước ta. Quân Tây Sơn chủ động rút lui chiến lược về phòng tuyến Tam Điệp - Biện Sơn.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eHành quân thần tốc \u0026amp; Quyết chiến chiến lược:\u003c/strong\u003e Nhận được tin báo cấp, ngày 22/12/1788 (tức 25/11 âm lịch), tại Núi Băng (Huế), Nguyễn Huệ chính thức làm lễ tế cáo trời đất, lên ngôi Hoàng đế lấy hiệu là Quang Trung, rồi lập tức chỉnh đốn quân đội hành quân ra Bắc. Tại Nghệ An và Thanh Hóa, ông tuyển thêm quân, tổ chức duyệt binh lớn và đưa ra lời dụ tướng sĩ đanh thép:\u003c/p\u003e\u003cp class=\"tl-q\"\u003e\"Đánh cho để chỏm tóc,\u003c/p\u003e\u003cp\u003eĐánh cho để đen răng,\u003c/p\u003e\u003cp\u003eĐánh cho nó chích luân bất phản,\u003c/p\u003e\u003cp\u003eĐánh cho nó phiến giáp bất hoàn,\u003c/p\u003e\u003cp\u003eĐánh cho sử tri Nam quốc anh hùng chi hữu chủ!\"\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eChiến dịch Tết Kỷ Dậu:\u003c/strong\u003e Đêm 30 Tết, quân Tây Sơn bất ngờ mở cuộc tổng tấn công thần tốc. Bằng các mũi tiến công táo bạo, kết hợp khiên chống đạn quấn rơm ướt, quân ta liên tiếp san phẳng các đồn lũy tiền tiêu của giặc. Sáng mùng 5 Tết, trận quyết chiến chiến lược diễn ra tại đồn Ngọc Hồi và Đống Đa (Hà Nội). Sầm Nghi Đống (tướng nhà Thanh) thắt cổ tự tử. Tôn Sĩ Nghị bàng hoàng kinh biến, chưa kịp đóng yên ngựa đã hoảng sợ bỏ chạy qua sông Hồng làm cầu phao gãy, hàng vạn quân Thanh chết đuối tắc nghẽn cả dòng sông.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Một trong những chiến công chống ngoại xâm oanh liệt, thần tốc và hiển hách nhất trong lịch sử dân tộc, bảo vệ toàn vẹn độc lập bờ cõi Đại Việt trước đế chế phong kiến phương Bắc hùng mạnh cuối cùng.\u003c/p\u003e",
    "40":  "\u003cp\u003e\u003cstrong\u003eBối cảnh \u0026amp; Nguyên nhân:\u003c/strong\u003e Thái thú quận Giao Chỉ là Tô Định nổi tiếng tàn bạo, tham lam. Thi Sách (lãnh tụ dòng dõi Lạc tướng tại Chu Diên) đứng lên phản kháng đã bị Tô Định giết hại nhằm uy hiếp tinh thần nhân dân.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến:\u003c/strong\u003e Mùa xuân năm 40, vợ của Thi Sách là Trưng Trắc cùng em gái là Trưng Nhị phất cờ khởi nghĩa tại cửa sông Hát (Hát Môn, Hà Nội). Lời thề ra trận vang vọng:\u003c/p\u003e\u003cp class=\"tl-q\"\u003e\"Một xin rửa sạch nước thù / Hai xin đem lại nghiệp xưa họ Hùng / Ba kẻo oan ức lòng chồng / Bốn xin vẻn vẹn sở công lênh này.\"\u003c/p\u003e\u003cp\u003eNghĩa quân nhanh chóng quét sạch chính quyền đô hộ, chiếm được 65 thành trì ở Giao Châu. Hai Bà Trưng lên ngôi vua, đóng đô ở Mê Linh, xóa bỏ các thứ thuế vô lý cho nhân dân. Năm 42, nhà Hán cử danh tướng Mã Viện đem đại quân sang đàn áp. Do chênh lệch lực lượng, Hai Bà Trưng hy sinh anh dũng tại sông Hát vào năm 43.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Cuộc khởi nghĩa đầu tiên do phụ nữ lãnh đạo trong lịch sử thế giới, biểu tượng vĩ đại cho tinh thần bất khuất, khẳng định quyền tự chủ của dân tộc.\u003c/p\u003e",
    "1975":  "\u003cp\u003e\u003cstrong\u003eBối cảnh \u0026amp; Chớp thời cơ:\u003c/strong\u003e Đầu năm 1975, nhận thấy quân đội Sài Gòn suy yếu nghiêm trọng sau khi mất chỗ dựa quân sự trực tiếp từ Mỹ, Bộ Chính trị quyết định mở cuộc Tổng tiến công và nổi dậy Xuân 1975 nhằm giải phóng hoàn toàn miền Nam.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eChiến dịch Hồ Chí Minh lịch sử:\u003c/strong\u003e Cuộc tổng tiến công diễn ra thần tốc qua 3 chiến dịch chiến lược lớn:\u003c/p\u003e\u003cp\u003eChiến dịch Tây Nguyên (mở màn bằng trận đánh hiểm yếu Buôn Ma Thuột khiến địch hoảng loạn rút chạy).\u003c/p\u003e\u003cp\u003eChiến dịch Huế - Đà Nẵng (quét sạch quân địch tại dải đất miền Trung).\u003c/p\u003e\u003cp\u003eChiến dịch Hồ Chí Minh (chiến dịch cuối cùng giải phóng Sài Gòn).\u003c/p\u003e\u003cp\u003eVào lúc 10 giờ 45 phút ngày 30/4/1975, hai chiếc xe tăng mang số hiệu 843 và 390 của quân giải phóng húc đổ cánh cổng sắt của Dinh Độc Lập. Tổng thống cuối cùng Dương Văn Minh tuyên bố đầu hàng vô điều kiện. Đúng 11 giờ 30 phút, lá cờ nửa đỏ nửa xanh ngôi sao vàng tung bay trên nóc dinh.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Thắng lợi vĩ đại nhất của lịch sử Việt Nam thế kỷ XX, kết thúc 21 năm kháng chiến chống Mỹ cứu nước và 30 năm chiến tranh giải phóng dân tộc trường kỳ, chấm dứt vĩnh viễn ách thống trị của chủ nghĩa thực dân, thống nhất non sông về một mối, đưa cả nước bước vào kỷ nguyên độc lập, thống nhất và tiến lên chủ nghĩa xã hội.\u003c/p\u003e",
    "1258":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Đế chế Mông Cổ trỗi dậy càn quét khắp lục địa Á - Âu. Năm 1257, tướng Ngột Lương Hợp Thai mang 3 vạn kỵ binh hung hãn tiến xuống xâm lược Đại Việt nhằm mở đường đánh bọc sườn nhà Nam Tống.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến \u0026amp; Chiến thuật:\u003c/strong\u003e Vua Trần Thái Tông cùng Thái sư Trần Thủ Độ trực tiếp chỉ huy chiến đấu. Tại trận Bình Lệ Nguyên, nhận thấy sức mạnh kỵ binh địch quá lớn, quân ta chủ động rút lui để bảo toàn lực lượng. Kinh thành Thăng Long được thực hiện kế sách “Vườn không nhà trống” (sơ tán toàn bộ nhân dân và lương thực). Quân Mông Cổ chiếm được thành trống không, thiếu thốn lương ăn nghiêm trọng, rơi vào cảnh đói khát, suy giảm ý chí trầm trọng.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eKết quả:\u003c/strong\u003e Thừa cơ giặc suy yếu, quân Trần phản công chiến lược tại Đông Bộ Đầu (Hà Nội). Quân địch đại bại, tháo chạy tán loạn về nước.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Bẻ gãy chiếc vuốt sắc đầu tiên của đế chế bất bại thế giới, khẳng định tính đúng đắn tuyệt đối của chiến thuật rút lui chiến lược và chiến tranh nhân dân.\u003c/p\u003e",
    "1400":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Cuối thế kỷ XIV, nhà Trần lâm vào thời kỳ khủng hoảng toàn diện, bất lực trong quản lý xã hội, vua quan suy đồi, bất lực trước các cuộc tấn công tàn phá liên tục của Chăm-pa từ phía Nam. Ngoại thích Hồ Quý Ly nắm giữ toàn bộ quyền hành thực tế trong triều.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện lập quốc:\u003c/strong\u003e Năm 1400, Hồ Quý Ly chính thức phế truất vua Trần, tự lên ngôi hoàng đế, đổi quốc hiệu thành Đại Ngu (Niềm vui lớn), lập nên nhà Hồ, chuyển kinh đô về Thành Tây Đô (Thành nhà Hồ, Thanh Hóa). Ông thực hiện một loạt các cải cách táo bạo, đi trước thời đại: phát hành tiền giấy đầu tiên (Thông bảo hội sao), hạn chế sở hữu ruộng đất và gia nô của quý tộc, mở rộng giáo dục thi cử khoa học toán học, cải cách y tế.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Là một cuộc cải cách mang tính đột phá mang tính tiến bộ cao, phản ánh tư duy đổi mới mạnh mẽ. Tuy nhiên, do phương thức chiếm ngôi vị và thực hiện cải cách quá vội vã, nhà Hồ đánh mất sự ủng hộ của đông đảo tầng lớp nhân dân và quý tộc cũ.\u003c/p\u003e",
    "1288":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Cay cú sau hai lần thảm bại nhục nhã, cuối năm 1287, nhà Nguyên dốc toàn lực lượng gồm 30 vạn quân cùng hàng trăm chiến thuyền lương thảo do Thoát Hoan và Ô Mã Nhi thống lĩnh sang xâm lược nước ta lần thứ ba.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eMưu kế vây hãm:\u003c/strong\u003e Trần Hưng Đạo nhận định giặc mạnh hay yếu phụ thuộc lớn vào đoàn thuyền lương. Tướng Trần Khánh Dư đã mưu trí mai phục, tiêu diệt toàn bộ đoàn thuyền lương khổng lồ của Trương Văn Hổ tại trận Vân Đồn (Quảng Ninh). Thoát Hoan rơi vào thế thiếu lương trầm trọng, buộc phải quyết định rút quân về nước bằng đường thủy qua sông Bạch Đằng.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eĐại thắng Bạch Đằng 1288:\u003c/strong\u003e Kế thừa bài học kinh nghiệm của Ngô Quyền năm 938, Trần Hưng Đạo một lần nữa cho cắm cọc gỗ đầu bịt sắt xuống lòng sông Bạch Đằng. Ngày 9/4/1288, quân ta nhử thuyền giặc vào trận địa lúc triều dâng. Khi thủy triều rút nhanh, các chiến thuyền lớn của Đại Việt ép giặc dồn vào bãi cọc.\u003c/p\u003e\u003cp\u003eThuyền giặc Nguyên (Ô Mã Nhi chỉ huy) ---\u0026gt; Bị cọc nhọn đâm thủng, mắc kẹt ---\u0026gt; Quân Trần phóng hỏa, ném đá, bắn tên tiễn biệt.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eKết quả:\u003c/strong\u003e Toàn bộ thủy quân nhà Nguyên bị hủy diệt hoàn toàn, tướng Ô Mã Nhi bị bắt sống tại trận. Thoát Hoan chạy đường bộ bàng hoàng thoát thân.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Đập tan vĩnh viễn mộng xâm lược xuống Đông Nam Á của đế quốc Nguyên - Mông hung hãn, đưa nghệ thuật thủy chiến Việt Nam đạt đến đỉnh cao chói lọi trong lịch sử quân sự thế giới.\u003c/p\u003e",
    "1995":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Thực hiện đường lối đối ngoại mới của thời kỳ Đổi mới: \"Việt Nam muốn là bạn với tất cả các nước trong cộng đồng quốc tế, phấn đấu vì hòa bình, độc lập và phát triển\", nước ta tích cực phá vỡ thế bao vây cô lập về ngoại giao.\u003c/p\u003e\u003cp\u003eHai sự kiện ngoại giao lịch sử trong cùng một tháng (tháng 7/1995):\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eNgày 11/7/1995:\u003c/strong\u003e Tổng thống Mỹ Bill Clinton và Thủ tướng Việt Nam Võ Văn Kiệt chính thức tuyên bố bình thường hóa quan hệ ngoại giao giữa hai nước, khép lại quá khứ chiến tranh đau thương, mở ra trang sử hợp tác toàn diện mang tính chiến lược giữa hai cựu thù.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eNgày 28/7/1995:\u003c/strong\u003e Việt Nam chính thức kết nạp trở thành thành viên thứ 7 của Hiệp hội các quốc gia Đông Nam Á (ASEAN) tại Hội nghị Bộ trưởng Ngoại giao ASEAN lần thứ 28 tại Brunei.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Bước đi đột phá vĩ đại trong chính sách đối ngoại, giúp Việt Nam hội nhập toàn diện với khu vực Đông Nam Á, phá vỡ hoàn toàn thế bị bao vây cô lập, tạo môi trường hòa bình, ổn định vững chắc để tập trung phát triển kinh tế trong nước.\u003c/p\u003e",
    "791":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Cuối thế kỷ VIII, nhà Đường suy yếu, quan đô hộ Cao Chính Bình tại thành Tống Bình khét tiếng tham ô, vơ vét của cải làm nhân dân vô cùng khốn khổ.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến cuộc chiến:\u003c/strong\u003e Khoảng năm 776, Phùng Hưng cùng em là Phùng Hải – vốn là những hào trưởng giàu lòng nghĩa hiệp ở Đường Lâm (Sơn Tây, Hà Nội) – khởi binh. Nhờ sức khỏe phi thường và mưu lược hơn người, Phùng Hưng tổ chức bao vây và đánh chiếm thành công phủ thành Tống Bình. Cao Chính Bình lo sợ quá mà sinh bệnh chết. Phùng Hưng tiếp quản chính sự, chăm lo đời sống nhân dân trong suốt 7 năm thì qua đời. Nhân dân suy tôn ông là Bố Cái Đại Vương (coi ông như cha mẹ của dân).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Cuộc khởi nghĩa chuẩn bị một bước đệm quan trọng về cả thực lực lẫn tâm lý chiến đấu cho người Việt, giáng đòn chí mạng vào chính quyền đô hộ nhà Đường.\u003c/p\u003e",
    "981":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Năm 979, Đinh Tiên Hoàng cùng con trưởng Đinh Liễn bị ám hại. Con thứ Đinh Toàn lên ngôi khi mới 6 tuổi. Nhà Tống chớp thời cơ đất nước đang rối ren liền điều quân ồ ạt sang xâm lược theo hai đường thủy, bộ. Trước nguy cơ mất nước, Thái hậu Dương Vân Nga và các triều thần đã đồng lòng đặt lợi ích quốc gia lên trên hết, trao chiếc áo long bào nhường ngôi cho Thập đạo Tướng quân Lê Hoàn.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến chiến sự:\u003c/strong\u003e Lê Hoàn lên ngôi vua (Lê Đại Hành), lập nên nhà Tiền Lê. Ông trực tiếp ra chiến trường, bố trí trận địa phòng thủ hiểm yếu tại sông Bạch Đằng và ải Chi Lăng. Quân dân Đại Cồ Việt chiến đấu quả cảm, chém chết tướng giặc Hầu Nhân Bảo trên sông, bẻ gãy hoàn toàn các cánh quân bộ. Quân Tống đại bại tháo chạy về nước.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Bảo vệ vững chắc nền độc lập non trẻ trước một đế chế Trung Hoa hùng mạnh, chứng minh sức mạnh của sự đoàn kết và tinh thần chuyển giao quyền lực vì đại cục quốc gia.\u003c/p\u003e",
    "1076":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sự phát triển ổn định của vương triều nhà Lý đòi hỏi phải xây dựng một hệ thống luật pháp, hành chính chuyên nghiệp dựa trên học vấn và thi cử bài bản chứ không chỉ dựa vào võ lực hay tăng lữ.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eQuá trình xây dựng:\u003c/strong\u003e\u003c/p\u003e\u003cp\u003eNăm 1070, vua Lý Thánh Tông cho xây dựng Văn Miếu để thờ Khổng Tử và các bậc hiền triết Nho giáo.\u003c/p\u003e\u003cp\u003eNăm 1076, vua Lý Nhân Tông cho lập thêm Quốc Tử Giám ngay bên cạnh Văn Miếu. Ban đầu đây là nơi học tập của hoàng tử, con em đại thần, sau mở rộng cho tất cả những người học giỏi trong thiên hạ.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Khẳng định sự hình thành của trường đại học đầu tiên tại Việt Nam, đánh dấu cột mốc Nho học chính thức trở thành hệ tư tưởng chính trong giáo dục, tạo nền móng đào tạo hàng loạt nhân tài, trạng nguyên phục vụ đất nước.\u003c/p\u003e",
    "1946":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Ngay sau khi độc lập, nước ta rơi vào tình thế hiểm nghèo \"ngàn cân treo sợi tóc\" (đói nghèo, dốt nát, quân đội các nước Đồng minh kéo vào). Thực dân Pháp bội ước, liên tiếp gây hấn, xả súng sát hại dân thường ở Hải Phòng, Hà Nội và gửi tối hậu thư đòi chính phủ ta phải giải tán lực lượng tự vệ, giao quyền kiểm soát thủ đô. Không thể nhân nhượng được nữa vì càng nhân nhượng Pháp càng lấn tới.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eLời kêu gọi lịch sử:\u003c/strong\u003e Đêm 19/12/1946, Chủ tịch Hồ Chí Minh ra Lời kêu gọi Toàn quốc kháng chiến:\u003c/p\u003e\u003cp class=\"tl-q\"\u003e\"Chúng ta thà hy sinh tất cả, chứ nhất định không chịu mất nước, nhất định không chịu làm nô lệ!\"\u003c/p\u003e\u003cp\u003eLời đài tiếng nói phát đi, quân và dân Thủ đô nổ súng mở màn cuộc chiến, ôm bom ba càng quyết tử giữ từng góc phố, ngôi nhà suốt 60 ngày đêm để bảo vệ cho Trung ương Đảng và chính phủ rút lui an toàn lên chiến khu Việt Bắc lập căn cứ kháng chiến trường kỳ.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Khẳng định quyết tâm bảo vệ thành quả Cách mạng Tháng Tám bằng mọi giá, bắt đầu cuộc chiến tranh nhân dân, trường kỳ kháng chiến toàn diện chống thực dân Pháp quay trở lại.\u003c/p\u003e",
    "1527":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Đầu thế kỷ XVI, nhà Hậu Lê bước vào giai đoạn suy thoái trầm trọng sau cái chết của Lê Thánh Tông. Các vua Lê Uy Mục (\"Vua quỷ\"), Lê Tương Dực (\"Vua lợn\") ăn chơi trụy lạc, đẩy đất nước vào cảnh loạn lạc, các thế lực đại thần tranh giành quyền lực giết hại lẫn nhau.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện chính:\u003c/strong\u003e Trong bối cảnh đó, Thái sư An Hưng vương Mạc Đăng Dung – một võ quan có công dẹp loạn – đã nắm giữ toàn bộ binh quyền. Năm 1527, ông chính thức ép vua Lê Cung Hoàng nhường ngôi, lập nên nhà Mạc (Bắc triều). Nhà Mạc cố gắng ổn định kinh tế, phát triển thương nghiệp, mở cửa cảng biển buôn bán và tổ chức nhiều kỳ thi trạng nguyên (tiêu biểu có trạng trình Nguyễn Bỉnh Khiêm).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eXung đột nội chiến:\u003c/strong\u003e Tuy nhiên, cựu thần nhà Lê là Nguyễn Kim không phục nhà Mạc, đã bỏ chạy vào Thanh Hóa, tìm lập một người dòng dõi nhà Lê lên ngôi (vua Lê Trang Tông), lập nên Nam triều. Đất nước rơi vào cuộc nội chiến khốc liệt Lê - Mạc kéo dài hơn 50 năm, gây tổn thất thảm khốc cho nhân dân cho đến khi nhà Mạc phải rút chạy lên vùng Cao Bằng (1592).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Mở đầu thời kỳ khủng hoảng và chia cắt chính trị sâu sắc kéo dài của chế độ phong kiến Việt Nam.\u003c/p\u003e",
    "939":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau đại thắng Bạch Đằng, đất nước sạch bóng quân thù, Ngô Quyền có đầy đủ uy danh và thực lực để kiến tạo một vương triều mới.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eHành động lịch sử:\u003c/strong\u003e Mùa xuân năm 939, Ngô Quyền chính thức xưng Vương (Ngô Vương), bỏ chức Tiết độ sứ của phong kiến Trung Hoa. Ông quyết định dời đô về lại Cổ Loa (vừa để khẳng định sự tiếp nối của nền độc lập thời Âu Lạc, vừa thể hiện quyết tâm đoạn tuyệt với các trung tâm hành chính cũ của thời Bắc thuộc). Ông thiết lập một triều đình mới: định ra trăm quan, quy định sắc phục, lễ nghi.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Khẳng định chủ quyền tối cao của một quốc gia độc lập có hoàng quy riêng, mở lối cho các triều đại chính thống sau này.\u003c/p\u003e",
    "1802":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau cái chết đột ngột của hoàng đế Quang Trung (1792), vương triều Tây Sơn nhanh chóng suy yếu do nội bộ lục đục, chia rẽ trầm trọng. Lợi dụng thời cơ này, Nguyễn Ánh với sự kiên trì chịu đựng suốt 20 năm cùng sự giúp đỡ độc lập vũ khí của người Pháp đã tập hợp lực lượng quay trở lại phản công dồn dập.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện chính:\u003c/strong\u003e Năm 1802, Nguyễn Ánh đánh bại hoàn toàn vương triều Tây Sơn, lên ngôi hoàng đế lấy hiệu là Gia Long, lập ra vương triều Nguyễn – triều đại phong kiến cuối cùng trong lịch sử Việt Nam, chọn Phú Xuân (Huế) làm kinh đô. Năm 1804, nhà vua đổi quốc hiệu nước ta thành Việt Nam.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eThành tựu \u0026amp; Hạn chế:\u003c/strong\u003e Nhà Nguyễn có công lớn trong việc nhất thống hoàn chỉnh toàn bộ lãnh thổ từ ải Nam Quan đến mũi Cà Mau, xây dựng Kinh thành Huế vĩ đại, biên soạn bộ luật Gia Long, vẽ bản đồ quốc gia và đặc biệt là thực thi, khẳng định chủ quyền vững chắc đối với hai quần đảo Hoàng Sa và Trường Sa thông qua đội hoàng sa kiêm quản Bắc Hải. Tuy nhiên về sau, các vua nhà Nguyễn (nhất là Minh Mạng, Thiệu Trị, Tự Đức) thực hiện chính sách \"bế quan tỏa cảng\", cấm đạo Công giáo gắt gao, khiến đất nước trở nên lạc hậu, suy yếu, mất đi cơ hội canh tân phát triển.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Định hình trọn vẹn bản đồ lãnh thổ Việt Nam hình chữ S thống nhất như ngày nay.\u003c/p\u003e",
    "1226":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Cuối thế kỷ XII - đầu thế kỷ XIII, nhà Lý suy thoái trầm trọng, vua quan ăn chơi sa đọa, hạn hán mất mùa liên miên, giặc giã nổi lên như ong. Thế lực quý tộc họ Trần trỗi dậy mãnh liệt, giúp nhà Lý dẹp loạn và nắm giữ toàn bộ binh quyền.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eCuộc chuyển giao êm đẹp:\u003c/strong\u003e Dưới sự đạo diễn chính trị tài tình của Điện tiền Chỉ huy sứ Trần Thủ Độ, vị vua cuối cùng của nhà Lý là nữ hoàng nhỏ tuổi Lý Chiêu Hoàng đã làm lễ nhường ngôi cho chồng là Trần Cảnh (Trần Thái Tông) vào tháng 1 năm 1226. Nhà Trần chính thức thiết lập quyền cai trị.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Giải quyết triệt để cuộc khủng hoảng chính trị cuối thời Lý. Nhà Trần thiết lập chế độ Thái thượng hoàng độc đáo (vua cha nhường ngôi sớm cho con rồi đứng sau cố vấn) giúp chính quyền trung ương cực kỳ vững mạnh, sẵn sàng đối phó với những thử thách lịch sử vĩ đại nhất.\u003c/p\u003e",
    "1862":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau khi bị sa lầy tại Đà Nẵng, Pháp chuyển hướng tấn công vào Gia Định (Nam Bộ) – vựa lúa lớn của đất nước nhằm cắt nguồn lương thực của triều đình. Dù nhân dân Nam Bộ nổi dậy kháng chiến khắp nơi (tiêu biểu như Nguyễn Trung Trực đốt cháy tàu Hy Vọng của Pháp trên sông Nhật Tảo), triều đình Tự Đức lại hoang mang, lo sợ phong trào khởi nghĩa của nông dân trong nước hơn là giặc ngoại xâm.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện:\u003c/strong\u003e Ngày 5/6/1862, triều đình nhà Nguyễn ký với Pháp bản Hiệp ước Nhâm Tuất. Theo đó, triều đình chấp nhận cắt đứt chủ quyền, nhượng hẳn 3 tỉnh miền Đông Nam Kỳ (Gia Định, Định Tường, Biên Hòa) và đảo Côn Lôn (Côn Đảo) cho Pháp, bồi thường 20 triệu quan tiền vàng, mở các cửa biển cho Pháp tự do buôn bán.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Bản hiệp ước bán nước đầu tiên, đánh dấu bước đầu hàng nhục nhã của triều đình phong kiến, gây làn sóng phẫn nộ sâu sắc trong nhân dân, khiến các thủ lĩnh nghĩa quân như Trương Định quyết định kháng lệnh vua để ở lại cùng dân đánh Pháp.\u003c/p\u003e",
    "1884":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Thực dân Pháp từng bước chiếm nốt 3 tỉnh miền Tây Nam Kỳ, rồi hai lần tiến quân ra đánh chiếm Bắc Kỳ (giết hại hai danh tướng Nguyễn Tri Phương và Hoàng Diệu dù quân ta đã lập chiến công chém đầu tướng giặc Garnier và Rivière tại trận Cầu Giấy). Sau khi vua Tự Đức qua đời (1883), nội bộ triều đình Huế khủng hoảng nghiêm trọng, liên tục thay đổi vua. Pháp đem hạm đội tàu chiến bắn phá cửa biển Thuận An, uy hiếp trực tiếp kinh thành Huế.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện:\u003c/strong\u003e Ngày 6/6/1884, đại diện triều đình ký với Pháp bản Hiệp ước Patenôtre (gồm 19 điều khoản). Hiệp ước này chính thức chia Việt Nam thành 3 chế độ cai trị hoàn toàn khác nhau dưới sự kiểm soát tối cao của Pháp: Nam Kỳ (thuộc địa Pháp), Trung Kỳ (bảo hộ nửa tự trị của triều đình) và Bắc Kỳ (bảo hộ nửa thuộc địa). Pháp nắm toàn bộ quyền ngoại giao, quân sự và kinh tế.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Cột mốc cay đắng đánh dấu sự sụp đổ hoàn toàn của nhà nước phong kiến độc lập Việt Nam. Kể từ đây, Việt Nam chính thức trở thành một nước thuộc địa nửa phong kiến.\u003c/p\u003e",
    "1858":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Giữa thế kỷ XIX, các nước tư bản phương Tây đẩy mạnh xâm lược các nước phương Đông để tìm kiếm thị trường và thuộc địa. Lấy cớ triều đình nhà Nguyễn cấm đạo và sát hại các giáo sĩ Công giáo, liên quân Pháp - Tây Ban Nha đã huy động hạm đội tàu chiến kéo đến nước ta.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện bùng nổ:\u003c/strong\u003e Ngày 1/9/1858, liên quân Pháp - Tây Ban Nha nổ súng tấn công bán đảo Đà Nẵng, chính thức mở đầu cuộc chiến tranh xâm lược Việt Nam. Đứng trước tình thế nguy ngập, danh tướng Nguyễn Tri Phương được cử làm tổng chỉ huy. Ông mưu trí áp đặt chiến thuật \"vườn không nhà trống\" kết hợp xây dựng phòng tuyến liên hoàn Đại đồn đắp cao chắc chắn, cầm chân thực dân Pháp suốt 5 tháng trên bán đảo, làm phá sản hoàn toàn kế hoạch \"Đánh nhanh thắng nhanh\" của chúng.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Cột mốc khởi đầu cho thời kỳ đau thương, mất mát nhưng cũng đầy anh dũng của dân tộc đối đầu với ách thực dân phương Tây hiện đại.\u003c/p\u003e",
    "905":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Đầu thế kỷ X, nhà Đường lâm vào tình trạng hỗn loạn, khủng hoảng trầm trọng trước phong trào khởi nghĩa nông dân Hoàng Sào và sự cát cứ của các tiết độ sứ. Quan thống trị tại An Nam là Độc Cô Tổn bị giáng chức.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eBước ngoặt lịch sử:\u003c/strong\u003e Nhận thời cơ vàng, Khúc Thừa Dụ – một hào trưởng có thế lực lớn tại Hồng Châu (Ninh Giang, Hải Dương ngày nay) – được nhân dân ủng hộ đã mang quân đánh chiếm thành Tống Bình, tự xưng là Tiết độ sứ. Để hợp thức hóa quyền lực và tránh sự can thiệp quân sự từ phương Bắc, ông buộc nhà Đường phải công nhận chức vị này. Con trai ông là Khúc Hạo tiếp quản (907) đã thực hiện những cải cách tiến bộ: chia lại đơn vị hành chính, định lại mức thuế nhẹ nhàng, lập sổ hộ khẩu, với phương châm: \"Chính sự cốt chuộng khoan dung, giản dị, nhân dân đều được yên vui\".\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Đóng vai trò là bước ngoặt vĩ đại xé toạc màn đêm Bắc thuộc, chấm dứt trên thực tế quyền cai trị của quan lại phương Bắc, đặt nền móng vững chắc cho nền độc lập hoàn toàn liền kề.\u003c/p\u003e",
    "1973":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Là kết quả trực tiếp của những thắng lợi quân sự vang dội của quân dân ta ở cả hai miền Nam - Bắc, đặc biệt là đại thắng \"Điện Biên Phủ trên không\" cuối năm 1972. Cuộc đàm phán kéo dài kỷ lục 4 năm 8 tháng với hàng trăm cuộc gặp gỡ công khai và bí mật vô cùng gay gắt.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện chính:\u003c/strong\u003e Ngày 27/1/1973, Hiệp định Paris về chấm dứt chiến tranh, lập lại hòa bình ở Việt Nam chính thức được ký kết giữa 4 bên. Nội dung cốt lõi: Mỹ và các nước đồng minh cam kết tôn trọng độc lập, chủ quyền, thống nhất và toàn vẹn lãnh thổ của Việt Nam; Mỹ phải rút toàn bộ quân viễn chinh và quân đồng minh về nước, phá bỏ các căn cứ quân sự, cam kết không tiếp tục can thiệp quân sự vào miền Nam.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Cột mốc hoàn thành thắng lợi mục tiêu \"Đánh cho Mỹ cút\", tạo ra sự thay đổi căn bản về tương quan lực lượng trên chiến trường có lợi tuyệt đối cho cách mạng, mở toang con đường tiến tới giải phóng hoàn toàn miền Nam.\u003c/p\u003e",
    "1941":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Năm 1939, Chiến tranh thế giới thứ hai bùng nổ. Năm 1940, phát-xít Nhật tràn vào Đông Dương, thực dân Pháp quỳ gối đầu hàng câu kết với Nhật cùng thống trị bóc lột, đặt nhân dân ta vào cảnh \"một cổ hai tròng\". Ngày 28/1/1941, sau 30 năm bôn ba, Lãnh tụ Nguyễn Ái Quốc trở về nước trực tiếp lãnh đạo cách mạng tại Pác Bó (Cao Bằng).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eThành lập Mặt trận:\u003c/strong\u003e Tháng 5/1941, Người chủ trì Hội nghị Ban Chấp hành Trung ương Đảng lần thứ 8, quyết định đặt nhiệm vụ giải phóng dân tộc lên hàng đầu, tạm gác khẩu hiệu cách mạng ruộng đất. Ngày 19/5/1941, Hội nghị quyết định thành lập Việt Nam Độc lập Đồng minh (gọi tắt là Việt Minh). Việt Minh tổ chức các \"Hội Cứu quốc\" thu hút mọi tầng lớp nhân dân không phân biệt tôn giáo, giai cấp, lứa tuổi cùng tham gia đánh Pháp đuổi Nhật. Từ mặt trận này, Đội Việt Nam Tuyên truyền Giải phóng quân (tiền thân của Quân đội Nhân dân Việt Nam) được thành lập vào ngày 22/12/1944.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Là biểu tượng tối cao của chiến lược đại đoàn kết dân tộc, tạo dựng lực lượng chính trị và lực lượng vũ trang quần chúng vững chắc, chuẩn bị trực tiếp cho cuộc Tổng khởi nghĩa giành độc lập.\u003c/p\u003e",
    "-700":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Giai đoạn phát triển đỉnh cao của thời kỳ đồ đồng và bắt đầu bước sang thời kỳ đồ sắt sớm tại khu vực Bắc Bộ và Bắc Trung Bộ ngày nay.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eChi tiết thành tựu:\u003c/strong\u003e Đỉnh cao của nền văn hóa này là kỹ thuật luyện kim đồng thau đạt đến trình độ siêu đẳng với phương pháp đúc khuôn sáp. Các hiện vật tiêu biểu gồm: Trống đồng Ngọc Lũ, trống đồng Cổ Loa, thạp đồng Đào Thịnh, vũ khí (dao găm, mũi tên đồng). Các hoa văn trên trống đồng phác họa sinh động đời sống tâm linh, hội hè, hình ảnh chim lạc, giã gạo, chèo thuyền của cư dân cổ.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eHệ quả \u0026amp; Ý nghĩa:\u003c/strong\u003e Là nền tảng vật chất khẳng định sự tồn tại của một nền văn minh bản địa rực rỡ trước khi chịu ảnh hưởng từ phương Bắc, chứng minh sự phân hóa giàu nghèo và tổ chức xã hội đã rất chặt chẽ.\u003c/p\u003e",
    "1471":  "\u003cp\u003e\u003cstrong\u003eBối cảnh ra đời:\u003c/strong\u003e Để quản lý một xã hội phát triển phức tạp và bảo vệ trật tự kỷ cương của nhà nước Hậu Lê thời thịnh trị, vua Lê Thánh Tông đã chỉ đạo biên soạn một bộ luật chính thức, hoàn chỉnh có tên gọi là Quốc triều hình luật (thường gọi là Luật Hồng Đức).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eNội dung cốt lõi và Tính tiến bộ:\u003c/strong\u003e Bộ luật gồm 6 quyển, 722 điều. Điểm độc đáo và tiến bộ vượt bậc của Luật Hồng Đức so với luật pháp phong kiến Trung Hoa đương thời là tính nhân văn sâu sắc. Luật đặc biệt chú trọng bảo vệ quyền lợi của người phụ nữ (quyền được chia tài sản bình đẳng, quyền ly hôn khi chồng bỏ bê), bảo vệ quyền lợi người già, trẻ em và người khuyết tật, trừng trị nghiêm khắc quan lại tham nhũng, đồng thời có nhiều điều luật bảo vệ đất đai, sản xuất nông nghiệp.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Là thành tựu lập pháp đỉnh cao của nền văn minh Đại Việt, một trong những bộ luật tiến bộ và toàn diện nhất thế giới thời trung cổ.\u003c/p\u003e",
    "1968":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Sau thất bại của chiến tranh đặc biệt, Mỹ trực tiếp đổ hàng vạn quân viễn chinh vào miền Nam tiến hành \"Chiến tranh cục bộ\", đồng thời mở cuộc chiến tranh phá hoại bằng không quân leo thang ra miền Bắc nhằm đè bẹp ý chí cách mạng. Nhận thấy sự bế tắc chiến lược của Mỹ trước thềm năm bầu cử Tổng thống Mỹ, Đảng ta quyết định mở một đòn tấn công bất ngờ táo bạo làm thay đổi cục diện.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến đột phá:\u003c/strong\u003e Đêm giao thừa Tết Mậu Thân 1968, quân giải phóng cùng nhân dân miền Nam đồng loạt mở cuộc Tổng tiến công và nổi dậy vào hơn 40 thành phố, thị xã, thị trấn trên khắp miền Nam. Điểm chấn động nhất là các chiến sĩ Biệt động Sài Gòn đã đánh thẳng vào các cơ quan đầu não thiêng liêng nhất của đối phương ngay tại sào huyệt: Đại sứ quán Mỹ, Dinh Độc Lập, Đài phát thanh, Bộ Tổng tham mưu quân đội Sài Gòn.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Mặc dù quân ta chịu tổn thất không nhỏ sau các đợt phản kích của địch, cuộc tiến công đã tạo ra một cú sốc chính trị kinh hoàng \"lên tận bàn nghị sự\" nước Mỹ. Nó làm phá sản hoàn toàn chiến lược \"Chiến tranh cục bộ\", buộc Tổng thống Mỹ Johnson phải tuyên bố ngừng ném bom miền Bắc, chấp nhận ngồi vào bàn đàm phán tại Paris và bắt đầu quá trình rút dần quân Mỹ về nước.\u003c/p\u003e",
    "1931":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Ngay sau khi Đảng ra đời, cuộc khủng hoảng kinh tế thế giới (1929-1933) tràn sang tàn phá thuộc địa, cộng thêm chính sách khủng bố trắng điên cuồng của Pháp sau khởi nghĩa Yên Bái của Việt Nam Quốc dân Đảng khiến đời sống công-nông rơi vào đường cùng.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến cao trào:\u003c/strong\u003e Dưới sự lãnh đạo của Đảng, một làn sóng đấu tranh bùng nổ mạnh mẽ trên cả nước. Đỉnh cao tuyệt đỉnh là phong trào đấu tranh của công nhân và nông dân ở hai tỉnh Nghệ An và Hà Tĩnh. Ngày 12/9/1930, hơn 8.000 nông dân Hưng Nguyên (Nghệ An) biểu tình rầm rộ, bị thực dân Pháp cho máy bay xả súng ném bom làm 217 người chết. Sự tàn bạo đó không làm lung lạc ý chí, quần chúng nổi dậy đập tan chính quyền tay sai ở các thôn xã. Các Ủy ban tự quản kiểu Xô Viết được thành lập: chia lại ruộng đất cho dân nghèo, bãi bỏ các thứ thuế vô lý, tổ chức học chữ Quốc ngữ, thành lập các đội tự vệ vũ trang. Phong trào bị Pháp đàn áp dã man bằng quân đội và máy bay vào giữa năm 1931.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Cuộc tổng diễn tập đầu tiên của quần chúng dưới sự lãnh đạo của Đảng Cộng sản, khẳng định khối liên minh công - nông vững chắc, chứng minh năng lực tự quản cách mạng mạnh mẽ của quần chúng.\u003c/p\u003e",
    "1009":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Cuối thời Tiền Lê, vua Lê Long Đĩnh (Lê Ngọa Triều) tàn bạo, hoang dâm vô độ khiến nhân dân và triều đình oán hận. Khi nhà vua qua đời năm 1009, triều đình không muốn tiếp tục dòng họ Lê độc tài.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eSự kiện chính:\u003c/strong\u003e Được sự đồng thuận cao của tầng lớp tăng lữ (đại diện là Thiền sư Vạn Hạnh) và các đại thần (tiêu biểu là Đào Cam Mộc), Tả thân vệ Điện tiền Chỉ huy sứ Lý Công Uẩn – một người đức độ, tài năng và học vấn uyên thâm – được tôn lên ngôi Hoàng đế (Lý Thái Tổ), sáng lập vương triều Lý kéo dài hơn 200 năm.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Khai sinh một triều đại thịnh trị, nhân văn lấy Phật giáo làm quốc giáo, đưa xã hội Việt Nam bước vào giai đoạn phát triển toàn diện, ổn định vững chắc.\u003c/p\u003e",
    "1077":  "\u003cp\u003e\u003cstrong\u003eBối cảnh lịch sử:\u003c/strong\u003e Thừa lúc vua Lý Nhân Tông còn nhỏ tuổi, nhà Tống âm mưu xâm lược Đại Việt bằng cách tích trữ lương thảo khổng lồ tại các căn cứ sát biên giới là Ung Châu, Khâm Châu, Liêm Châu.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eChiến lược thiên tài:\u003c/strong\u003e Thái úy Lý Thường Kiệt tổng chỉ huy quân đội Đại Việt đã đưa ra một quyết sách táo bạo áp dụng nghệ thuật \"Tiên phát chế nhân\" (Tấn công trước để tự vệ). Cuối năm 1075, ông bất ngờ chỉ huy hơn 10 vạn quân đánh thẳng sang đất Tống, triệt phá sạch các kho tàng tích trữ của địch rồi nhanh chóng rút quân về nước lập trận tuyến phòng thủ dọc sông Như Nguyệt (sông Cầu, Bắc Ninh).\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eDiễn biến \u0026amp; Kết quả:\u003c/strong\u003e Khi quân Tống do Quách Quỳ chỉ huy tràn sang, bị chặn đứng bên bờ sông Như Nguyệt. Giữa đêm tối hưu quạnh, để khích lệ tinh thần binh sĩ đang mỏi mệt, Lý Thường Kiệt đã cho người vào đền thờ ngâm vang bài thơ thần \"Nam quốc sơn hà\":\u003c/p\u003e\u003cp\u003eNam quốc sơn hà Nam đế cư\u003c/p\u003e\u003cp\u003eTiệt nhiên định phận tại thiên thư\u003c/p\u003e\u003cp\u003eNhư hà nghịch lỗ lai xâm phạm\u003c/p\u003e\u003cp\u003eNhữ đẳng hành khan thủ bại hư.\u003c/p\u003e\u003cp\u003eQuân Tống hoang mang tột độ, quân ta thừa thế tổng phản công, đập tan quân giặc. Lý Thường Kiệt chủ động mở đường giảng hòa để giữ thể diện cho nước lớn, giữ vững hòa bình lâu dài.\u003c/p\u003e\u003cp\u003e\u003cstrong\u003eÝ nghĩa:\u003c/strong\u003e Bản tuyên ngôn độc lập đầu tiên của dân tộc vang lên khẳng định chủ quyền thiêng liêng. Nghệ thuật quân sự chủ động tiến công kết hợp tâm lý chiến đạt tầm cao đỉnh cao.\u003c/p\u003e"
};
